import React from "react";
import {
  AcademicCapIcon,
  ClipboardDocumentListIcon,
  ChartBarIcon,
  StarIcon,
  BookOpenIcon,
  ChatBubbleLeftRightIcon,
} from "@heroicons/react/24/solid";

export default function Home() {
  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-100 via-purple-100 to-pink-100 p-10 font-sans relative">
      {/* Hero Section */}
      <div className="text-center py-16">
        <h1 className="text-5xl md:text-6xl font-extrabold text-gray-900 mb-4">
          Welcome to Smart Learning
        </h1>
        <p className="text-gray-700 text-lg md:text-xl max-w-2xl mx-auto">
          Manage your tasks, track progress, and enhance your learning experience all in one place.
        </p>
        <button className="mt-8 bg-gradient-to-r from-purple-500 to-indigo-500 text-white px-6 py-3 rounded-2xl shadow-lg hover:scale-105 transform transition duration-300">
          Get Started
        </button>
      </div>

      {/* Features Section */}
      <div className="mt-20 grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-8">

        {/* Resources Card */}
        <Card
          icon={<BookOpenIcon className="h-12 w-12 text-indigo-500 mb-4" />}
          title="Resources"
          desc="Access study materials, notes, and guides to boost your knowledge."
        />

        {/* Tasks Card */}
        <Card
          icon={<ClipboardDocumentListIcon className="h-12 w-12 text-green-500 mb-4" />}
          title="Tasks"
          desc="Stay organized and track your daily learning tasks efficiently."
        />

        {/* Progress Card */}
        <Card
          icon={<ChartBarIcon className="h-12 w-12 text-purple-500 mb-4" />}
          title="Progress"
          desc="Monitor your performance and growth with detailed analytics."
        />

        {/* Quizzes Card */}
        <Card
          icon={<AcademicCapIcon className="h-12 w-12 text-pink-500 mb-4" />}
          title="Quizzes"
          desc="Test your knowledge with interactive quizzes and challenges."
        />

        {/* Ratings Card */}
        <Card
          icon={<StarIcon className="h-12 w-12 text-yellow-500 mb-4" />}
          title="Ratings"
          desc="Rate courses and view feedback from other learners."
        />
      </div>

      {/* Footer Call-to-Action */}
      <div className="mt-20 text-center">
        <h2 className="text-3xl font-bold text-gray-900 mb-4">
          Ready to boost your learning?
        </h2>
        <button className="bg-gradient-to-r from-purple-500 to-indigo-500 text-white px-6 py-3 rounded-2xl shadow-lg hover:scale-105 transform transition duration-300">
          Explore Now
        </button>
      </div>

      {/* Floating Community Chat Button */}
      <div className="fixed bottom-6 right-6">
        <button className="flex items-center gap-2 bg-gradient-to-r from-indigo-500 to-purple-600 text-white px-5 py-3 rounded-full shadow-xl hover:scale-110 transition">
          <ChatBubbleLeftRightIcon className="h-6 w-6" />
          Community
        </button>
      </div>
    </div>
  );
}

// Reusable Card Component
function Card({ icon, title, desc }) {
  return (
    <div className="bg-white/80 backdrop-blur-md rounded-2xl p-6 shadow-xl hover:scale-105 transform transition duration-300">
      {icon}
      <h3 className="text-xl font-bold mb-2">{title}</h3>
      <p className="text-gray-700">{desc}</p>
    </div>
  );
}
